        "path": "Program.cs",
        "content": "using System;\nusing System.Threading.Tasks;\nusing BinanceTradingTool.Core;\nusing BinanceTradingTool.Strategies;\n\nnamespace BinanceTradingTool\n{\n    /// <summary>\n    /// Entry point for the Binance Trading Bot.\n    /// This bot simulates trading decisions based on market data without connecting to a live API.\n    /// </summary>\n    internal class Program\n    {\n        static async Task Main(string[] args)\n        {\n            Console.WriteLine(\"=== Binance Trading Bot (Simulated, No API) ===\");\n            Console.WriteLine();\n\n            // Load sample market data from embedded resources or generate it\n            var marketData = MarketDataProvider.GenerateSampleData(\"BTCUSDT\", 100);\n\n            // Initialize the trading strategy (moving average crossover)\n            var strategy = new MovingAverageCrossoverStrategy(shortWindow: 5, longWindow: 20);\n\n            // Run the backtest\n            var engine = new TradingEngine(strategy);\n            var results = engine.Backtest(marketData);\n\n            // Display results\n            Console.WriteLine(\"Backtest Results:\");\n            Console.WriteLine($\"Total Trades: {results.TotalTrades}\");\n            Console.WriteLine($\"Wins: {results.Wins}\");\n            Console.WriteLine($\"Losses: {results.Losses}\");\n            Console.WriteLine($\"Final Balance: {results.FinalBalance:F2} USDT\");\n            Console.WriteLine($\"Return: {results.ReturnPercentage:F2}%\");\n\n            // Simulate a live trading loop (without API)\n            Console.WriteLine();\n            Console.WriteLine(\"Starting simulated live trading (press Ctrl+C to stop)...\");\n            await SimulateLiveTrading(strategy);\n        }\n\n        private static async Task SimulateLiveTrading(MovingAverageCrossoverStrategy strategy)\n        {\n            var random = new Random();\n            var prices = new List<decimal> { 50000m, 50100m, 50250m, 50150m, 50300m };\n            int index = 0;\n\n            while (true)\n            {\n                // Simulate new price arrival\n                decimal newPrice = prices[index % prices.Length] + (decimal)(random.NextDouble() * 200 - 100);\n                prices.Add(newPrice);\n\n                // Evaluate strategy\n                var signal = strategy.Evaluate(prices);\n                if (signal == TradeSignal.Buy)\n                {\n                    Console.WriteLine($\"[{DateTime.Now:T}] BUY signal at {newPrice:F2}\");\n                }\n                else if (signal == TradeSignal.Sell)\n                {\n                    Console.WriteLine($\"[{DateTime.Now:T}] SELL signal at {newPrice:F2}\");\n                }\n\n                index++;\n                await Task.Delay(2000); // Wait 2 seconds between ticks\n            }\n        }\n    }\n}\n"
