        "path": "Core/TradingEngine.cs",
        "content": "using System;\nusing System.Collections.Generic;\nusing BinanceTradingTool.Strategies;\n\nnamespace BinanceTradingTool.Core\n{\n    /// <summary>\n    /// Represents the result of a backtest.\n    /// </summary>\n    public class BacktestResult\n    {\n        public int TotalTrades { get; set; }\n        public int Wins { get; set; }\n        public int Losses { get; set; }\n        public decimal FinalBalance { get; set; }\n        public decimal ReturnPercentage { get; set; }\n    }\n\n    /// <summary>\n    /// Engine that runs a trading strategy over historical data.\n    /// </summary>\n    public class TradingEngine\n    {\n        private readonly ITradingStrategy _strategy;\n\n        public TradingEngine(ITradingStrategy strategy)\n        {\n            _strategy = strategy ?? throw new ArgumentNullException(nameof(strategy));\n        }\n\n        /// <summary>\n        /// Runs a backtest on the provided market data.\n        /// </summary>\n        /// <param name=\"marketData\">List of (timestamp, price) tuples.</param>\n        /// <returns>A BacktestResult with performance metrics.</returns>\n        public BacktestResult Backtest(List<(DateTime Time, decimal Price)> marketData)\n        {\n            if (marketData == null || marketData.Count < 2)\n                throw new ArgumentException(\"Market data must contain at least two data points.\");\n\n            var prices = new List<decimal>();\n            decimal balance = 10000m; // Starting balance in USDT\n            decimal holding = 0m;      // Amount of crypto held\n            int totalTrades = 0;\n            int wins = 0;\n            int losses = 0;\n\n            foreach (var (time, price) in marketData)\n            {\n                prices.Add(price);\n\n                if (prices.Count < 2)\n                    continue;\n\n                var signal = _strategy.Evaluate(prices);\n\n                if (signal == TradeSignal.Buy && holding == 0)\n                {\n                    // Buy with all available balance\n                    holding = balance / price;\n                    balance = 0;\n                    totalTrades++;\n                }\n                else if (signal == TradeSignal.Sell && holding > 0)\n                {\n                    // Sell all holdings\n                    decimal newBalance = holding * price;\n                    if (newBalance > balance)\n                        wins++;\n                    else\n                        losses++;\n                    balance = newBalance;\n                    holding = 0;\n                    totalTrades++;\n                }\n            }\n\n            // If still holding, sell at last price\n            if (holding > 0)\n            {\n                balance = holding * marketData[^1].Price;\n            }\n\n            decimal initialBalance = 10000m;\n            decimal returnPct = ((balance - initialBalance) / initialBalance) * 100;\n\n            return new BacktestResult\n            {\n                TotalTrades = totalTrades,\n                Wins = wins,\n                Losses = losses,\n                FinalBalance = balance,\n                ReturnPercentage = returnPct\n            };\n        }\n    }\n}\n"
    },
