        "path": "Core/MarketDataProvider.cs",
        "content": "using System;\nusing System.Collections.Generic;\n\nnamespace BinanceTradingTool.Core\n{\n    /// <summary>\n    /// Provides market data for backtesting without requiring a live API.\n    /// Generates synthetic price data resembling BTC/USDT.\n    /// </summary>\n    public static class MarketDataProvider\n    {\n        /// <summary>\n        /// Generates a list of (DateTime, decimal) tuples simulating historical price data.\n        /// </summary>\n        /// <param name=\"symbol\">The trading pair symbol (e.g., \"BTCUSDT\").</param>\n        /// <param name=\"count\">Number of data points to generate.</param>\n        /// <returns>A list of timestamped prices.</returns>\n        public static List<(DateTime Time, decimal Price)> GenerateSampleData(string symbol, int count)\n        {\n            if (string.IsNullOrWhiteSpace(symbol))\n                throw new ArgumentException(\"Symbol cannot be null or empty.\", nameof(symbol));\n            if (count < 2)\n                throw new ArgumentException(\"Count must be at least 2.\", nameof(count));\n\n            var data = new List<(DateTime, decimal)>();\n            var random = new Random(42); // Fixed seed for reproducibility\n            decimal basePrice = symbol switch\n            {\n                \"BTCUSDT\" => 50000m,\n                \"ETHUSDT\" => 3000m,\n                _ => 100m\n            };\n\n            DateTime startTime = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc);\n            decimal currentPrice = basePrice;\n\n            for (int i = 0; i < count; i++)\n            {\n                // Simulate price movement with a random walk\n                decimal change = (decimal)(random.NextDouble() * 2 - 1) * 200; // +/- 200\n                currentPrice += change;\n                if (currentPrice < 0) currentPrice = 0.01m; // Prevent negative prices\n\n                data.Add((startTime.AddMinutes(i * 5), Math.Round(currentPrice, 2)));\n            }\n\n            return data;\n        }\n    }\n}\n"
    },
