        "content": "namespace BinanceTradingTool.Strategies\n{\n    /// <summary>\n    /// Possible trading signals.\n    /// </summary>\n    public enum TradeSignal\n    {\n        Hold,\n        Buy,\n        Sell\n    }\n\n    /// <summary>\n    /// Interface for all trading strategies.\n    /// </summary>\n    public interface ITradingStrategy\n    {\n        /// <summary>\n        /// Evaluates the current market data and returns a trading signal.\n        /// </summary>\n        /// <param name=\"prices\">List of historical prices (most recent last).</param>\n        /// <returns>Buy, Sell, or Hold signal.</returns>\n        TradeSignal Evaluate(List<decimal> prices);\n    }\n}\n"
