        "path": "Strategies/MovingAverageCrossoverStrategy.cs",
        "content": "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nnamespace BinanceTradingTool.Strategies\n{\n    /// <summary>\n    /// Implements a simple moving average crossover strategy.\n    /// Generates a Buy signal when the short-term MA crosses above the long-term MA,\n    /// and a Sell signal when it crosses below.\n    /// </summary>\n    public class MovingAverageCrossoverStrategy : ITradingStrategy\n    {\n        private readonly int _shortWindow;\n        private readonly int _longWindow;\n        private TradeSignal? _lastSignal;\n\n        /// <summary>\n        /// Initializes the strategy with given window sizes.\n        /// </summary>\n        /// <param name=\"shortWindow\">Number of periods for the short moving average (e.g., 5).</param>\n        /// <param name=\"longWindow\">Number of periods for the long moving average (e.g., 20).</param>\n        public MovingAverageCrossoverStrategy(int shortWindow, int longWindow)\n        {\n            if (shortWindow <= 0 || longWindow <= 0)\n                throw new ArgumentException(\"Window sizes must be positive.\");\n            if (shortWindow >= longWindow)\n                throw new ArgumentException(\"Short window must be less than long window.\");\n\n            _shortWindow = shortWindow;\n            _longWindow = longWindow;\n        }\n\n        /// <summary>\n        /// Evaluates the price list and returns a trading signal.\n        /// </summary>\n        /// <param name=\"prices\">List of prices (most recent last). Must have at least longWindow elements.</param>\n        /// <returns>Buy, Sell, or Hold.</returns>\n        public TradeSignal Evaluate(List<decimal> prices)\n        {\n            if (prices == null || prices.Count < _longWindow)\n                return TradeSignal.Hold;\n\n            // Calculate moving averages\n            decimal shortMA = prices.TakeLast(_shortWindow).Average();\n            decimal longMA = prices.TakeLast(_longWindow).Average();\n\n            TradeSignal signal;\n\n            if (shortMA > longMA)\n            {\n                signal = TradeSignal.Buy;\n            }\n            else if (shortMA < longMA)\n            {\n                signal = TradeSignal.Sell;\n            }\n            else\n            {\n                signal = TradeSignal.Hold;\n            }\n\n            // Only generate signal on crossover (change from previous state)\n            if (_lastSignal.HasValue && signal == _lastSignal.Value)\n            {\n                return TradeSignal.Hold;\n            }\n\n            _lastSignal = signal;\n            return signal;\n        }\n    }\n}\n"
    },
