        "path": "Tests/TradingEngineTests.cs",
        "content": "using System;\nusing System.Collections.Generic;\nusing BinanceTradingTool.Core;\nusing BinanceTradingTool.Strategies;\nusing Xunit;\n\nnamespace BinanceTradingTool.Tests\n{\n    /// <summary>\n    /// Unit tests for the TradingEngine and related components.\n    /// </summary>\n    public class TradingEngineTests\n    {\n        [Fact]\n        public void Backtest_WithUpTrend_ShouldReturnPositiveReturn()\n        {\n            // Arrange\n            var strategy = new MovingAverageCrossoverStrategy(2, 5);\n            var engine = new TradingEngine(strategy);\n\n            // Create steadily increasing prices\n            var data = new List<(DateTime, decimal)>();\n            decimal price = 100m;\n            for (int i = 0; i < 50; i++)\n            {\n                data.Add((DateTime.UtcNow.AddMinutes(i * 5), price));\n                price += 5m; // Upward trend\n            }\n\n            // Act\n            var result = engine.Backtest(data);\n\n            // Assert\n            Assert.True(result.FinalBalance > 10000m, \"Should have profit in uptrend\");\n            Assert.True(result.ReturnPercentage > 0);\n            Assert.True(result.TotalTrades > 0);\n        }\n\n        [Fact]\n        public void Backtest_WithDownTrend_ShouldReturnNegativeReturn()\n        {\n            // Arrange\n            var strategy = new MovingAverageCrossoverStrategy(2, 5);\n            var engine = new TradingEngine(strategy);\n\n            // Create steadily decreasing prices\n            var data = new List<(DateTime, decimal)>();\n            decimal price = 50000m;\n            for (int i = 0; i < 50; i++)\n            {\n                data.Add((DateTime.UtcNow.AddMinutes(i * 5), price));\n                price -= 200m; // Downward trend\n                if (price < 0) price = 0.01m;\n            }\n\n            // Act\n            var result = engine.Backtest(data);\n\n            // Assert\n            Assert.True(result.FinalBalance < 10000m, \"Should have loss in downtrend\");\n            Assert.True(result.ReturnPercentage < 0);\n        }\n\n        [Fact]\n        public void Backtest_WithInsufficientData_ShouldThrow()\n        {\n            // Arrange\n            var strategy = new MovingAverageCrossoverStrategy(5, 20);\n            var engine = new TradingEngine(strategy);\n            var data = new List<(DateTime, decimal)> { (DateTime.UtcNow, 100m) }; // Only one data point\n\n            // Act & Assert\n            Assert.Throws<ArgumentException>(() => engine.Backtest(data));\n        }\n\n        [Fact]\n        public void Evaluate_WithShortAboveLong_ReturnsBuy()\n        {\n            // Arrange\n            var strategy = new MovingAverageCrossoverStrategy(2, 5);\n            var prices = new List<decimal> { 10, 11, 12, 13, 14, 15 }; // Short MA > Long MA\n\n            // Act\n            var signal = strategy.Evaluate(prices);\n\n            // Assert\n            Assert.Equal(TradeSignal.Buy
